import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_packages(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-2] if '/' in proj['path'] else proj['path']
        for fw in proj['frameworks']:
            key = f\"{name}/{fw['framework']}\"
            for pkg in fw['topLevelPackages']:
                result.setdefault(key, {})[pkg['id']] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)

changes = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(key, {})
    ap = a.get(key, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes.append((key, pkg, bv, av))

if changes:
    print('CHANGES:')
    for key, pkg, bv, av in changes:
        print(f'  {key}: {pkg} {bv} -> {av}')
else:
    print('NO CHANGES - all packages resolve identically')
"

